import{_ as t,c as o,o as a,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Quota Governance: Protection + Warmup | Antigravity-Manager","description":"Learn Antigravity Tools quota governance: use Quota Protection to preserve critical models and Smart Warmup for automatic warmup when quota restores.","frontmatter":{"title":"Quota Governance: Protection + Warmup | Antigravity-Manager","sidebarTitle":"Quota Governance","subtitle":"Quota Governance: Combined Quota Protection + Smart Warmup Strategy","description":"Learn Antigravity Tools quota governance: use Quota Protection to preserve critical models and Smart Warmup for automatic warmup when quota restores.","tags":["quota","warmup","accounts","proxy"],"prerequisite":["start-add-account","start-proxy-and-first-client"],"order":999},"headers":[],"relativePath":"lbjlaq/Antigravity-Manager/advanced/quota/index.md","filePath":"lbjlaq/Antigravity-Manager/advanced/quota/index.md"}'),n={name:"lbjlaq/Antigravity-Manager/advanced/quota/index.md"};function i(s,e,d,l,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="quota-governance-quota-protection-smart-warmup-combined-strategy" tabindex="-1">Quota Governance: Quota Protection + Smart Warmup Combined Strategy <a class="header-anchor" href="#quota-governance-quota-protection-smart-warmup-combined-strategy" aria-label="Permalink to &quot;Quota Governance: Quota Protection + Smart Warmup Combined Strategy&quot;">​</a></h1><p>You&#39;re running Antigravity Tools stably, but there&#39;s one thing you fear most: your primary model&#39;s quota gets &quot;quietly drained,&quot; and by the time you actually need it, you find it&#39;s already too low to use.</p><p>This lesson is about <strong>Quota Governance</strong>: use Quota Protection to preserve critical models; use Smart Warmup to perform a &quot;light warmup&quot; when quota restores, reducing unexpected failures.</p><h2 id="what-is-quota-governance" tabindex="-1">What is Quota Governance? <a class="header-anchor" href="#what-is-quota-governance" aria-label="Permalink to &quot;What is Quota Governance?&quot;">​</a></h2><p><strong>Quota Governance</strong> refers to controlling &quot;how quota is spent&quot; using two linked mechanisms in Antigravity Tools: when a model&#39;s remaining quota falls below a threshold, Quota Protection adds that model to the account&#39;s <code>protected_models</code>, and requests for that model prioritize avoiding it; when quota returns to 100%, Smart Warmup triggers a minimal warmup request and applies a 4-hour cooldown using a local history file.</p><h2 id="what-you-ll-learn" tabindex="-1">What You&#39;ll Learn <a class="header-anchor" href="#what-you-ll-learn" aria-label="Permalink to &quot;What You&#39;ll Learn&quot;">​</a></h2><ul><li>Enable Quota Protection to let low-quota accounts automatically &quot;yield,&quot; reserving high-value models for critical requests</li><li>Enable Smart Warmup for automatic warmup when quota restores (and understand how 4-hour cooldown affects trigger frequency)</li><li>Understand where <code>quota_protection</code> / <code>scheduled_warmup</code> / <code>protected_models</code> fields take effect</li><li>Know which model names get normalized into &quot;protection groups&quot; (and which don&#39;t)</li></ul><h2 id="your-current-struggles" tabindex="-1">Your Current Struggles <a class="header-anchor" href="#your-current-struggles" aria-label="Permalink to &quot;Your Current Struggles&quot;">​</a></h2><ul><li>You think you&#39;re &quot;rotating accounts,&quot; but you&#39;re actually continuously consuming the same type of high-value models</li><li>You only discover low quota when it&#39;s too late—even Claude Code or clients drain quota in background warmup</li><li>You enabled warmup, but don&#39;t know when it actually triggers, whether there&#39;s a cooldown, or if it affects quota</li></ul><h2 id="when-to-use-this-approach" tabindex="-1">When to Use This Approach <a class="header-anchor" href="#when-to-use-this-approach" aria-label="Permalink to &quot;When to Use This Approach&quot;">​</a></h2><ul><li>You have multiple account pools and want critical models to have remaining quota during &quot;important moments&quot;</li><li>You don&#39;t want to manually monitor quota restore time and want the system to automatically do a &quot;light verification after restore&quot;</li></ul><h2 id="🎒-preparation" tabindex="-1">🎒 Preparation <a class="header-anchor" href="#🎒-preparation" aria-label="Permalink to &quot;🎒 Preparation&quot;">​</a></h2><div class="warning custom-block"><p class="custom-block-title">Prerequisite</p><p>This lesson assumes you can already:</p><ul><li>See the account list on the <strong>Accounts</strong> page and manually refresh quota</li><li>Have started the local reverse proxy (at minimum, can access <code>/healthz</code>)</li></ul><p>If not yet working, see <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/proxy-and-first-client/">Start Local Reverse Proxy &amp; First Client</a></strong>.</p></div><p>Additionally, Smart Warmup writes to a local history file <code>warmup_history.json</code>. It&#39;s placed in the data directory—you can learn about data directory location and backup methods in <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/start/first-run-data/">First Run Essentials: Data Directory, Logs, Tray, and Auto-startup</a></strong>.</p><h2 id="core-approach" tabindex="-1">Core Approach <a class="header-anchor" href="#core-approach" aria-label="Permalink to &quot;Core Approach&quot;">​</a></h2><p>This &quot;combined strategy&quot; is actually straightforward:</p><ul><li>Quota Protection handles &quot;stop wasting&quot;: when a model falls below threshold, mark it as protected, and prioritize avoiding that account when requesting that model (model-level, not a blanket account disable).</li><li>Smart Warmup handles &quot;verify when quota restores&quot;: when a model returns to 100%, trigger a lightweight request to confirm the link works, with 4-hour cooldown to avoid repeated disturbances.</li></ul><p>Their corresponding config fields are in the frontend <code>AppConfig</code>:</p><ul><li><code>quota_protection.enabled / threshold_percentage / monitored_models</code> (see <code>src/types/config.ts</code>)</li><li><code>scheduled_warmup.enabled / monitored_models</code> (see <code>src/types/config.ts</code>)</li></ul><p>The actual logic determining &quot;whether to skip this account when requesting this model&quot; is in the backend TokenManager:</p><ul><li>The account file&#39;s <code>protected_models</code> participates in filtering in <code>get_token(..., target_model)</code> (see <code>src-tauri/src/proxy/token_manager.rs</code>)</li><li><code>target_model</code> first gets normalized (<code>normalize_to_standard_id</code>), so variants like <code>claude-sonnet-4-5-thinking</code> get collapsed into the same &quot;protection group&quot; (see <code>src-tauri/src/proxy/common/model_mapping.rs</code>)</li></ul><h2 id="next-lesson-preview" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><blockquote><p>In the next lesson, we learn <strong><a href="/docs/opencodedocs/lbjlaq/Antigravity-Manager/advanced/monitoring/">Proxy Monitor: Request Logs, Filtering, Detail Reconstruction, and Export</a></strong>, turning API calls into an auditable evidence chain.</p></blockquote><h2 id="follow-along" tabindex="-1">Follow Along <a class="header-anchor" href="#follow-along" aria-label="Permalink to &quot;Follow Along&quot;">​</a></h2><h3 id="step-1-first-get-quota-data-visible" tabindex="-1">Step 1: First, Get Quota Data &quot;Visible&quot; <a class="header-anchor" href="#step-1-first-get-quota-data-visible" aria-label="Permalink to &quot;Step 1: First, Get Quota Data &quot;Visible&quot;&quot;">​</a></h3><p><strong>Why</strong> Quota Protection makes judgments based on <code>quota.models[].percentage</code> in accounts. Without quota data, protection logic can&#39;t do anything for you.</p><p>Path: Open the <strong>Accounts</strong> page, click the refresh button in the toolbar (single account or bulk refresh both work).</p><p><strong>What you should see</strong>: Account rows show quota percentages for each model (e.g., 0-100) and reset time.</p><h3 id="step-2-enable-smart-warmup-in-settings-optional-but-recommended" tabindex="-1">Step 2: Enable Smart Warmup in Settings (Optional, but Recommended) <a class="header-anchor" href="#step-2-enable-smart-warmup-in-settings-optional-but-recommended" aria-label="Permalink to &quot;Step 2: Enable Smart Warmup in Settings (Optional, but Recommended)&quot;">​</a></h3><p><strong>Why</strong> Smart Warmup&#39;s goal isn&#39;t &quot;save quota,&quot; but &quot;self-check the link when quota restores.&quot; It only triggers when model quota reaches 100%, and has a 4-hour cooldown.</p><p>Path: Enter <strong>Settings</strong>, switch to the account-related settings area, turn on the <strong>Smart Warmup</strong> toggle, then check the models you want to monitor.</p><p>Don&#39;t forget to save settings.</p><p><strong>What you should see</strong>: Smart Warmup expands to show a model list; at least 1 model should remain checked.</p><h3 id="step-3-enable-quota-protection-and-set-threshold-monitored-models" tabindex="-1">Step 3: Enable Quota Protection and Set Threshold + Monitored Models <a class="header-anchor" href="#step-3-enable-quota-protection-and-set-threshold-monitored-models" aria-label="Permalink to &quot;Step 3: Enable Quota Protection and Set Threshold + Monitored Models&quot;">​</a></h3><p><strong>Why</strong> Quota Protection is the core of &quot;preserve reserves&quot;: when a monitored model&#39;s quota percentage <code>&lt;= threshold_percentage</code>, it writes that model to the account file&#39;s <code>protected_models</code>, and subsequent requests for that model prioritize avoiding these accounts.</p><p>Path: In <strong>Settings</strong>, turn on <strong>Quota Protection</strong>.</p><ol><li>Set threshold (<code>1-99</code>)</li><li>Check the models you want to monitor (at least 1)</li></ol><div class="tip custom-block"><p class="custom-block-title">A good starting config</p><p>If you don&#39;t want to overthink, start with the default <code>threshold_percentage=10</code> (see <code>src/pages/Settings.tsx</code>).</p></div><p><strong>What you should see</strong>: Quota Protection keeps at least 1 model checked (the UI blocks you from unchecking the last one).</p><h3 id="step-4-confirm-protection-group-normalization-won-t-trip-you-up" tabindex="-1">Step 4: Confirm &quot;Protection Group Normalization&quot; Won&#39;t Trip You Up <a class="header-anchor" href="#step-4-confirm-protection-group-normalization-won-t-trip-you-up" aria-label="Permalink to &quot;Step 4: Confirm &quot;Protection Group Normalization&quot; Won&#39;t Trip You Up&quot;">​</a></h3><p><strong>Why</strong> When TokenManager makes quota protection judgments, it first normalizes <code>target_model</code> to a standard ID (<code>normalize_to_standard_id</code>). For example, <code>claude-sonnet-4-5-thinking</code> gets normalized to <code>claude-sonnet-4-5</code>.</p><p>This means:</p><ul><li>You check <code>claude-sonnet-4-5</code> in Quota Protection</li><li>When you actually request <code>claude-sonnet-4-5-thinking</code></li></ul><p>Protection still triggers (because they belong to the same group).</p><p><strong>What you should see</strong>: When an account&#39;s <code>protected_models</code> contains <code>claude-sonnet-4-5</code>, requests for <code>claude-sonnet-4-5-thinking</code> prioritize avoiding that account.</p><h3 id="step-5-when-you-need-immediate-verification-use-manual-warmup-to-trigger-warmup" tabindex="-1">Step 5: When You Need Immediate Verification, Use &quot;Manual Warmup&quot; to Trigger Warmup <a class="header-anchor" href="#step-5-when-you-need-immediate-verification-use-manual-warmup-to-trigger-warmup" aria-label="Permalink to &quot;Step 5: When You Need Immediate Verification, Use &quot;Manual Warmup&quot; to Trigger Warmup&quot;">​</a></h3><p><strong>Why</strong> The scheduled Smart Warmup scan cycle is once every 10 minutes (see <code>src-tauri/src/modules/scheduler.rs</code>). If you want to verify the link immediately, manual warmup is more direct.</p><p>Path: Open the <strong>Accounts</strong> page, click the &quot;Warmup&quot; button in the toolbar:</p><ul><li>No account selected: triggers bulk warmup (calls <code>warm_up_all_accounts</code>)</li><li>Account(s) selected: triggers warmup for each selected account (calls <code>warm_up_account</code>)</li></ul><p><strong>What you should see</strong>: A toast appears, with content from the backend return string (e.g., &quot;Warmup task triggered ...&quot;).</p><h2 id="checkpoint-✅" tabindex="-1">Checkpoint ✅ <a class="header-anchor" href="#checkpoint-✅" aria-label="Permalink to &quot;Checkpoint ✅&quot;">​</a></h2><ul><li>You can see model quota percentages for each account on the Accounts page (proves quota data path is OK)</li><li>You can enable Quota Protection / Smart Warmup in Settings and successfully save config</li><li>You understand <code>protected_models</code> is a &quot;model-level&quot; restriction: an account might only be avoided for certain models</li><li>You know warmup has a 4-hour cooldown: clicking warmup repeatedly in a short time might show &quot;skipped/cooldown&quot; related messages</li></ul><h2 id="pitfall-alerts" tabindex="-1">Pitfall Alerts <a class="header-anchor" href="#pitfall-alerts" aria-label="Permalink to &quot;Pitfall Alerts&quot;">​</a></h2><h3 id="_1-you-enabled-quota-protection-but-it-never-takes-effect" tabindex="-1">1) You Enabled Quota Protection, But It Never Takes Effect <a class="header-anchor" href="#_1-you-enabled-quota-protection-but-it-never-takes-effect" aria-label="Permalink to &quot;1) You Enabled Quota Protection, But It Never Takes Effect&quot;">​</a></h3><p>The most common reason: accounts don&#39;t have <code>quota</code> data. Protection logic in the backend needs to first read <code>quota.models[]</code> to judge thresholds (see <code>src-tauri/src/proxy/token_manager.rs</code>).</p><p>You can go back to <strong>Step 1</strong> and refresh quota first.</p><h3 id="_2-why-do-only-some-models-get-treated-as-protection-groups" tabindex="-1">2) Why Do Only Some Models Get Treated as &quot;Protection Groups&quot;? <a class="header-anchor" href="#_2-why-do-only-some-models-get-treated-as-protection-groups" aria-label="Permalink to &quot;2) Why Do Only Some Models Get Treated as &quot;Protection Groups&quot;?&quot;">​</a></h3><p>TokenManager&#39;s normalization of <code>target_model</code> is &quot;whitelist-based&quot;: only explicitly listed model names get mapped to standard IDs (see <code>src-tauri/src/proxy/common/model_mapping.rs</code>).</p><p>After normalization, the logic is: use the normalized name (standard ID or original model name) to match the account&#39;s <code>protected_models</code> field. If match succeeds, that account is skipped (see <code>src-tauri/src/proxy/token_manager.rs:555-560, 716-719</code>). This means:</p><ul><li>Models within the whitelist (like <code>claude-sonnet-4-5-thinking</code>) get normalized to standard ID (<code>claude-sonnet-4-5</code>), then check if in <code>protected_models</code></li><li>When models outside the whitelist fail normalization, they fall back to original model name, and still match <code>protected_models</code></li></ul><p>In other words, quota protection judgments take effect for &quot;all model names,&quot; but whitelisted models get normalized first.</p><h3 id="_3-why-do-manual-scheduled-warmups-need-the-proxy-running" tabindex="-1">3) Why Do Manual/Scheduled Warmups Need the Proxy Running? <a class="header-anchor" href="#_3-why-do-manual-scheduled-warmups-need-the-proxy-running" aria-label="Permalink to &quot;3) Why Do Manual/Scheduled Warmups Need the Proxy Running?&quot;">​</a></h3><p>Warmup requests eventually hit the local proxy&#39;s internal endpoint: <code>POST /internal/warmup</code> (see routes in <code>src-tauri/src/proxy/server.rs</code>, and implementation in <code>src-tauri/src/proxy/handlers/warmup.rs</code>). If you didn&#39;t start the proxy service, warmup fails.</p><p>Additionally, the port warmup uses comes from config: <code>proxy.port</code> (if config read fails, it falls back to <code>8045</code>, see <code>src-tauri/src/modules/quota.rs</code>).</p><h2 id="lesson-summary" tabindex="-1">Lesson Summary <a class="header-anchor" href="#lesson-summary" aria-label="Permalink to &quot;Lesson Summary&quot;">​</a></h2><ul><li>Quota Protection does &quot;stop the loss&quot;: below threshold, write model to <code>protected_models</code>, prioritize avoiding that account when requesting that model</li><li>Smart Warmup does &quot;self-check on restore&quot;: only triggers at 100%, scans every 10 minutes, with 4-hour cooldown</li><li>Both depend on the &quot;quota refresh&quot; path: first have <code>quota.models[]</code>, then governance has a foundation</li></ul><h2 id="next-lesson-preview-1" tabindex="-1">Next Lesson Preview <a class="header-anchor" href="#next-lesson-preview-1" aria-label="Permalink to &quot;Next Lesson Preview&quot;">​</a></h2><p>Quota governance solves &quot;how to spend more stably.&quot; The next lesson recommends continuing with <strong>Proxy Monitor</strong>, turning request logs, account hits, and model mapping into a replayable evidence chain.</p><hr><h2 id="appendix-source-code-reference" tabindex="-1">Appendix: Source Code Reference <a class="header-anchor" href="#appendix-source-code-reference" aria-label="Permalink to &quot;Appendix: Source Code Reference&quot;">​</a></h2><details><summary><strong>Click to expand source code locations</strong></summary><blockquote><p>Last updated: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Feature</th><th>File Path</th><th>Lines</th></tr></thead><tbody><tr><td>Quota Protection UI (threshold, model selection, keep at least 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/QuotaProtection.tsx#L13-L168" target="_blank" rel="noreferrer"><code>src/components/settings/QuotaProtection.tsx</code></a></td><td>13-168</td></tr><tr><td>Smart Warmup UI (default checked on enable, keep at least 1)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/components/settings/SmartWarmup.tsx#L14-L120" target="_blank" rel="noreferrer"><code>src/components/settings/SmartWarmup.tsx</code></a></td><td>14-120</td></tr><tr><td>Quota governance config fields (<code>quota_protection</code> / <code>scheduled_warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/types/config.ts#L54-L94" target="_blank" rel="noreferrer"><code>src/types/config.ts</code></a></td><td>54-94</td></tr><tr><td>Default threshold and default config (<code>threshold_percentage: 10</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src/pages/Settings.tsx#L20-L51" target="_blank" rel="noreferrer"><code>src/pages/Settings.tsx</code></a></td><td>20-51</td></tr><tr><td>Write/restore <code>protected_models</code> (threshold judgment and persist)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/token_manager.rs#L254-L467" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/token_manager.rs</code></a></td><td>254-467</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Protection group normalization (<code>normalize_to_standard_id</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/common/model_mapping.rs#L230-L254" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/common/model_mapping.rs</code></a></td><td>230-254</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>Manual warmup commands (<code>warm_up_all_accounts</code> / <code>warm_up_account</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/commands/mod.rs#L167-L212" target="_blank" rel="noreferrer"><code>src-tauri/src/commands/mod.rs</code></a></td><td>167-212</td></tr><tr><td>Warmup implementation (calls internal endpoint <code>/internal/warmup</code>)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/modules/quota.rs#L271-L512" target="_blank" rel="noreferrer"><code>src-tauri/src/modules/quota.rs</code></a></td><td>271-512</td></tr><tr><td>Internal warmup endpoint implementation (construct request + call upstream)</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/handlers/warmup.rs#L3-L220" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/handlers/warmup.rs</code></a></td><td>3-220</td></tr></tbody></table></details>',71)])])}const m=t(n,[["render",i]]);export{p as __pageData,m as default};
